/**
 * Math Vocabulary Identity System — CIE 0580 (228 papers)
 *
 * Each word is a full "identity card" with:
 * - Exam frequency (core/high/medium/low tier)
 * - Multiple senses (一词多义)
 * - Real exam phrases (真题句式)
 * - KP/topic associations
 * - Collocations
 *
 * Data sources: ExamHub vocabulary-cie.json + vocab-frequency-analysis.json
 *   + vocab-disambig.json + vocab-collocations.json + 228 paper JSONs
 */

export type VocabSense = { context: string; meaning: { zh: string; en: string }; example: string };
export type ExamPhrase = { en: string; zh: string; paperCount: number };
export type ExamFreq = { paperCount: number; questionCount: number; paperPct: number; tier: 'core' | 'high' | 'medium' | 'low' };

export type MathWord = {
  id: string; en: string; zh: string; desc: string;
  senses: VocabSense[];
  examFreq: ExamFreq;
  examPhrases: ExamPhrase[];
  kpIds: string[];
  topicIds: string[];
  collocations: string[];
  tags: string[];
};

