const _byWord = new Map<string, MathWord>();
const _byId = new Map<string, MathWord>();
for (const w of MATH_VOCAB) { _byId.set(w.id, w); _byWord.set(w.en.toLowerCase(), w); }

export function lookupWord(en: string): MathWord | undefined { return _byWord.get(en.toLowerCase().trim()); }
export function getWordById(id: string): MathWord | undefined { return _byId.get(id); }

export function findVocabInText(text: string): { word: MathWord; start: number; end: number }[] {
  const lower = text.toLowerCase();
  const matches: { word: MathWord; start: number; end: number }[] = [];
  const sorted = [...MATH_VOCAB].sort((a, b) => b.en.length - a.en.length);
  const used = new Set<number>();
  for (const w of sorted) {
    const term = w.en.toLowerCase();
    if (term.length < 3) continue; // skip very short words
    let pos = 0;
    while (true) {
      const idx = lower.indexOf(term, pos);
      if (idx === -1) break;
      const before = idx === 0 || /[^a-zA-Z]/.test(lower[idx - 1]);
      const after = idx + term.length >= lower.length || /[^a-zA-Z]/.test(lower[idx + term.length]);
      if (before && after) {
        let overlap = false;
        for (let i = idx; i < idx + term.length; i++) { if (used.has(i)) { overlap = true; break; } }
        if (!overlap) {
          matches.push({ word: w, start: idx, end: idx + term.length });
          for (let i = idx; i < idx + term.length; i++) used.add(i);
        }
      }
      pos = idx + 1;
    }
  }
  return matches.sort((a, b) => a.start - b.start);
}

/** Get words by frequency tier */
export function getWordsByTier(tier: 'core' | 'high' | 'medium' | 'low'): MathWord[] {
  return MATH_VOCAB.filter(w => w.examFreq.tier === tier);
}

/** Get hub words (appear in ≥50% of papers) */
export function getCoreWords(): MathWord[] { return getWordsByTier('core'); }

export const VOCAB_COUNT = MATH_VOCAB.length;
